class Solution {
    public boolean canTransform(String start, String result) {
        int m = start.length();
        int n = result.length();

        boolean[][] dp = new boolean[m + 1][n + 1];

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (start.charAt(i - 1) == result.charAt(j - 1)) {
                    dp[i][j] = (start.charAt(i - 1) == 'X') ? (j == 1) : (dp[i - 1][j - 1] || dp[i - 1][j]);
                } else if (start.charAt(i - 1) == 'L') {
                    dp[i][j] = dp[i - 1][j] || dp[i][j - 1];
                } else {
                    dp[i][j] = dp[i - 1][j] || dp[i][j - 1];
                }
            }
        }
        return dp[m][n];
    }
}
